/// NetworkTables data types.
enum NT_Type {
  NT_UNASSIGNED(0),
  NT_BOOLEAN(1),
  NT_DOUBLE(2),
  NT_STRING(4),
  NT_RAW(8),
  NT_BOOLEAN_ARRAY(16),
  NT_DOUBLE_ARRAY(32),
  NT_STRING_ARRAY(64),
  NT_RPC(128),
  NT_INTEGER(256),
  NT_FLOAT(512),
  NT_INTEGER_ARRAY(1024),
  NT_FLOAT_ARRAY(2048);

  final int value;
  const NT_Type(this.value);

  static NT_Type fromValue(int value) => switch (value) {
    0 => NT_UNASSIGNED,
    1 => NT_BOOLEAN,
    2 => NT_DOUBLE,
    4 => NT_STRING,
    8 => NT_RAW,
    16 => NT_BOOLEAN_ARRAY,
    32 => NT_DOUBLE_ARRAY,
    64 => NT_STRING_ARRAY,
    128 => NT_RPC,
    256 => NT_INTEGER,
    512 => NT_FLOAT,
    1024 => NT_INTEGER_ARRAY,
    2048 => NT_FLOAT_ARRAY,
    _ => throw ArgumentError('Unknown value for NT_Type: $value'),
  };
}

